const articles = $input.all().map(i => i.json).filter(a => a.id);

if (articles.length === 0) {
  return [{ json: { done: true, processed: 0, remaining: 0 } }];
}

const articleList = articles.map((a, i) => 
  `Article ${i} (id=${a.id}, topic=${a.topic}): ${a.title}\n${a.content_snippet || 'No content available'}`
).join('\n\n---\n\n');

const systemPrompt = `You analyze news articles. For each article, return a JSON object with key "articles" containing an array. Each element must have:
- "id": the article id (number)
- "summary": a 2-3 sentence summary explaining what the article is about and why it matters
- "relevance_score": 1-10 rating. BE STRICT with scoring — most articles should be 4-7. Only give 8-10 to articles that are DIRECTLY about the core topics below.
- "tags": array of up to 5 keyword tags

STRICT topic scoring:
- "ai": 9-10 ONLY for articles directly about: building AI agents, agentic workflows, AI-assisted coding (vibe coding), using Claude/Cursor/Copilot for development, context window management, AI memory systems, prompt engineering patterns. 6-8 for general LLM news, model releases, AI tools. 3-5 for tangentially related AI content (AI policy, AI art, general tech using AI buzzwords).
- "music": 9-10 for music creation tools, DAW tips, AI music generation. 5-7 for general music discussion.
- "computers": 9-10 for homelab builds, self-hosting guides, networking. 5-7 for general hardware/IT.
- "tech": 9-10 for significant tech news. 5-7 for minor updates.

Return ONLY valid JSON.`;

const requestBody = JSON.stringify({
  model: 'gpt-4o-mini',
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: articleList }
  ],
  temperature: 0.3,
  max_tokens: 2000
});

return [{ json: { requestBody, articleIds: articles.map(a => a.id), count: articles.length } }];

const aiResponse = $json;
const content = aiResponse?.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  return [{ json: { error: 'Failed to parse OpenAI response', raw: content.substring(0, 200) } }];
}

const articles = parsed.articles || [];
const updates = [];

for (const a of articles) {
  if (!a.id) continue;
  const esc = (v) => v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  const tags = JSON.stringify(a.tags || []);
  const score = Math.min(10, Math.max(1, parseInt(a.relevance_score) || 5));
  updates.push(`UPDATE news_articles SET ai_summary = ${esc(a.summary)}, ai_tags = '${tags.replace(/'/g, "\\'")}', relevance_score = ${score} WHERE id = ${a.id}`);
}

if (updates.length === 0) {
  return [{ json: { processed: 0, sql: 'SELECT 1' } }];
}

return [{ json: { processed: updates.length, sql: updates.join(';\n') } }];
